import { useState } from "react";
import QrScanner from "react-qr-scanner";
import "./App.css";

function App() {
  const [data, setData] = useState("Brak danych");

  const previewStyle = {
    height: 240,
    width: 320,
  };

  const handleScan = (result) => {
    if (result) {
      setData(result.text || result);
    }
  };

  const handleError = (err) => {
    console.error(err);
  };

  return (
    <div className="App">
      <header className="App-header">
        <h1>Czytnik QR</h1>

        <QrScanner
          onScan={handleScan}
          onError={handleError}
          style={previewStyle}
        />

        <p><strong>Odczytany kod:</strong> {data}</p>
      </header>
    </div>
  );
}

export default App;
